（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:12+00:00", "source_pdf_sha1": "e8fbac390cd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "139", "s": "1103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地法規與土地登記", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "地政"}'::jsonb, NULL),
  ('promotion-f29af906-moex-00045', 'promotion-f29af906', 'promotion-f29af906-moex-110-b4990932', 'sub-promotion-f29af906-04', NULL, 'essay', '近幾年國內地價不斷攀升，試以經濟圖形說明此一現象在短期會對土地
